/** @format */

import React, { useState } from "react";
import Logo from "../images/Accesss-Autonomy-Logo.ico";
import { Link } from "react-router-dom";
import ReactSwitch from "react-switch";
import Burger from "./BurgerMenu";
import {
  FaHome,
  FaChild,
  FaThLarge,
  FaGithub,
  FaLinkedinIn,
} from "react-icons/fa";

const Nav = (props) => {
  const [showNav, setShowNav] = useState();

  const toggleTheme = (event) => {
    props.onChangeSwitch(event);
  };

  const handleMenu = (e) => {
    if (e) {
      setShowNav("nav-toggle");
      console.log("test")
    } else {
      setShowNav("");
      console.log("test2")
    }


  };

  return (
    <>
      <Burger menuToggled={handleMenu} />
      <div className="nav-main" id={showNav}>
        <div id={"nav-main-logo"}>
          <img src={Logo} alt="AccessAutonomy Logo"></img>
        </div>
        <div id={"nav-main-list"}>
          <Link to="/">
            <FaHome />
          </Link>
          <Link to="/about">
            <FaChild />
          </Link>
          <Link to="/projects">
            <FaThLarge />
          </Link>
          <Link to="/blog">
            <FaGithub />
          </Link>
          <Link to="/contacts">
            <FaLinkedinIn />
          </Link>
          <div className="switch">
            <ReactSwitch
              value={props.themeToggled}
              onChange={toggleTheme}
              checked={props.themeToggled === "dark"}
            />
          </div>
        </div>
      </div>
    </>
  );
};

export default Nav;
